function BudgetBars(){const[ref,v]=useReveal();const items=[{l:"Garden clearance",lo:2,hi:5,c:C.sage},{l:"Landscaping",lo:5,hi:15,c:C.sage},{l:"Lower gnd waterproof",lo:3,hi:8,c:C.terracotta},{l:"Kitchen upgrade",lo:4,hi:12,c:C.clay},{l:"Bathroom refit",lo:2,hi:6,c:C.clay},{l:"Finishes + snag",lo:2,hi:5,c:C.lightGrey},{l:"Building regs",lo:1,hi:3,c:C.fee},{l:"Contingency",lo:3,hi:8,c:C.fee}];const mx=Math.max(...items.map(i=>i.hi));const tl=items.reduce((a,b)=>a+b.lo,0);const th=items.reduce((a,b)=>a+b.hi,0);return(<div ref={ref} style={{margin:"24px 0",opacity:v?1:0,transition:"opacity 0.7s ease 0.1s"}}><Lab color={C.accentDark}>COMPLETION BUDGET</Lab><div style={{display:"flex",flexDirection:"column",gap:"3px"}}>{items.map((it,i)=>(<div key={i} style={{display:"flex",alignItems:"center",gap:"7px"}}><div style={{width:"100px",textAlign:"right",fontFamily:"'Inter',sans-serif",fontSize:"9px",color:C.warmGrey,flexShrink:0}}>{it.l}</div><div style={{flex:1,position:"relative",height:"14px"}}><div style={{position:"absolute",left:0,top:"2px",height:"10px",width:v?`${(it.lo/mx)*100}%`:"0%",background:it.c,opacity:0.32,borderRadius:"1.5px",transition:`width 0.6s ease ${0.1+i*0.05}s`}}/><div style={{position:"absolute",left:0,top:"2px",height:"10px",width:v?`${(it.hi/mx)*100}%`:"0%",background:it.c,opacity:0.1,borderRadius:"1.5px",transition:`width 0.8s ease ${0.1+i*0.05}s`}}/></div><div style={{width:"48px",fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:it.c,flexShrink:0}}>£{it.lo}–{it.hi}K</div></div>))}</div><div style={{textAlign:"right",marginTop:"10px"}}><div style={{fontFamily:"'Playfair Display',serif",fontSize:"clamp(20px,3.5vw,28px)",color:C.accentDark}}>£{tl}K – £{th}K</div><Cap>to finish what was started</Cap></div></div>);}

