                <div key={i}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(17px,2.8vw,22px)",color:i===0?C.accentDark:C.paper}}>{s.v}</div><Cap>{s.s}</Cap></div>
